INSERT INTO "public"."grammar" ("id", "name", "note", "sort_order", "updated_at", "deleted_at") VALUES (1, 'být', '<p>Sloveso <b>být</b> je v angličtině nepravidelné a má různé tvary podle osoby a času.</p><br /><dl><dt>já jsem</dt><dd>I am</dd><dt>ty jsi</dt><dd>you are</dd><dt>on je</dt><dd>he is</dd><dt>ona je</dt><dd>she is</dd><dt>ono je</dt><dd>it is</dd><dt>my jsme</dt><dd>we are</dd><dt>vy jste</dt><dd>you are</dd><dt>oni jsou</dt><dd>they are</dd></dl><br /><p>V mluveném jazyce se běžně používají zkrácené tvary:</p><br /><dl ><dt>já jsem</dt><dd>I''m</dd><dt>ty jsi</dt><dd>you''re</dd><dt>on je</dt><dd>he''s</dd><dt>ona je</dt><dd>she''s</dd><dt>ono je</dt><dd>it''s</dd><dt>my jsme</dt><dd>we''re</dd><dt>vy jste</dt><dd>you''re</dd><dt>oni jsou</dt><dd>they''re</dd></dl>', 1, '2026-05-15 09:16:18.787939+00', null), (2, 'být - zápor', '<p>V angličtině se zápor tvoří pomocí pomocného slovesa <b>not</b>, které se přidává za sloveso.</p><br /><dl ><dt>já nejsem</dt><dd>I am not</dd><dt>ty nejsi</dt><dd>you are not</dd><dt>on není</dt><dd>he is not</dd><dt>ona není</dt><dd>she is not</dd><dt>ono není</dt><dd>it is not</dd><dt>my nejsme</dt><dd>we are not</dd><dt>vy nejste</dt><dd>you are not</dd><dt>oni nejsou</dt><dd>they are not</dd></dl><br /><p>V mluveném jazyce se běžně používají zkrácené tvary:</p><br /><dl><dt>já nejsem</dt><dd>I''m not</dd><dt>ty nejsi</dt><dd>you aren''t</dd><dt>on není</dt><dd>he isn''t</dd><dt>ona není</dt><dd>she isn''t</dd><dt>ono není</dt><dd>it isn''t</dd><dt>my nejsme</dt><dd>we aren''t</dd><dt>vy nejste</dt><dd>you aren''t</dd><dt>oni nejsou</dt><dd>they aren''t</dd></dl><br /><p>Existuje i druhá varianta zkráceného tvaru, která je vnímána s větším důrazem na negaci:</p><br /><dl><dt>já nejsem</dt><dd>I''m not</dd><dt>ty nejsi</dt><dd>you''re not</dd><dt>on není</dt><dd>he''s not</dd><dt>ona není</dt><dd>she''s not</dd><dt>ono není</dt><dd>it''s not</dd><dt>my nejsme</dt><dd>we''re not</dd><dt>vy nejste</dt><dd>you''re not</dd><dt>oni nejsou</dt><dd>they''re not</dd></dl>', 2, '2026-05-15 09:21:15.487617+00', null), (3, 'být - otázky ano/ne', '<p>Otázky ano/ne se tvoří inverzí slovesa <b>být</b> a podmětu.</p><br /><p><b>sloveso + podmět</b></p><br /><dl><dt>Jsem hladový?</dt><dd>Am I hungry?</dd><dt>Jsi hladový?</dt><dd>Are you hungry?</dd><dt>Je hladový?</dt><dd>Is he hungry?</dd><dt>Je hladová?</dt><dd>Is she hungry?</dd><dt>Je to hladové?</dt><dd>Is it hungry?</dd><dt>Jsme hladoví?</dt><dd>Are we hungry?</dd><dt>Jste hladoví?</dt><dd>Are you hungry?</dd><dt>Jsou hladoví?</dt><dd>Are they hungry?</dd></dl><br /><p>Obdobně se tvoří záporné verze otázek. Většinou se používá zkrácená verze.</p><br /><dl><dt>Nejsem hladový?</dt><dd>Am I not hungry?</dd><dt>Nejsi hladový?</dt><dd>Aren''t you hungry?</dd><dt>Není hladový?</dt><dd>Isn''t hungry?</dd><dt>Není hladová?</dt><dd>Isn''t she hungry?</dd><dt>Není to hladové?</dt><dd>Isn''t it hungry?</dd><dt>Nejsme hladoví?</dt><dd>Aren''t we hungry?</dd><dt>Nejste hladoví?</dt><dd>Aren''t you hungry?</dd><dt>Nejsou hladoví?</dt><dd>Aren''t they hungry?</dd></dl><br /><p>Běžně se na tázací věty odpovídá nejen ano / ne, ale i příslušným tvarem slovesa být. S ano se běžně používá nezkrácený tvar, s ne zkrácený.</p><br /><dl><dt>Ano, jsem.</dt><dd>Yes, I am.</dd><dt>Ano, jsi.</dt><dd>Yes, you are.</dd><dt>Ano, je.</dt><dd>Yes, he/she/it is.</dd><dt>Ano, jsme</dt><dd>Yes, we are.</dd><dt>Ano, jste.</dt><dd>Yes, you are.</dd><dt>Ano, jsou.</dt><dd>Yes, they are.</dd></dl><br /><dl><dt>Ne, nejsem.</dt><dd>Yes, I''m not.</dd><dt>Ne, nejsi.</dt><dd>Yes, you aren''t.</dd><dt>Ne, není.</dt><dd>Yes, he/she/it isn''t.</dd><dt>Ne, nejsme</dt><dd>Yes, we aren''t.</dd><dt>Ne, nejste.</dt><dd>Yes, you aren''t.</dd><dt>Ne, nejsou.</dt><dd>Yes, they aren''t.</dd></dl>', 3, '2026-05-15 09:21:53.735203+00', null), (4, 'být - otázky s tázacím zájmenem', '<p>Otázky s tázacím zájmenem se tvoří inverzí slovesa <b>být</b> a podmětu, přičemž tázací zájmeno stojí na začátku věty.</p><br /><p><b>tázací zájmeno + sloveso + podmět ?</b></p><br /><dl><dt>Kdo jsem?</dt><dd>Who am I?</dd><dt>Kdo jsi?</dt><dd>Who are you?</dd><dt>Kdo je to? (on)</dt><dd>Who is he?</dd><dt>Kdo je to? (ona)</dt><dd>Who is she?</dd><dt>Kdo je to? (ono)</dt><dd>What is it?</dd><dt>Kdo jsme?</dt><dd>Who are we?</dd><dt>Kdo jste?</dt><dd>Who are you?</dd><dt>Kdo jsou?</dt><dd>Who are they?</dd></dl><br /><p>Negativní varianty otázek se používají pouze výjmečně.</p>', 4, '2026-05-15 09:25:57.176911+00', null), (5, 'množné číslo', '<p><b>Počitatelná podstatná jména</b> označují věci, které lze spočítat (např. book, apple, car).</p><br /><p><b>Nepočitatelná podstatná jména</b> označují látky nebo abstraktní pojmy, které nelze počítat jako jednotlivé kusy (např. water, sugar, information).</p><br /><p><b>Množné číslo</b> tvoříme u počitatelných podstatných jmen obvykle přidáním -s, u slov končících na -ch, -sh, -x, -s, -z přidáváme -es.</p><br /><dl><dt>book</dt><dd>books</dd><dt>box</dt><dd>boxes</dd></dl><br /><p>Některá slova mají nepravidelné tvary.Pokud má podstatné jméno nepravidelný množný tvar, bude ten tvar uveden samostatně.</p><br /><dl><dt>child</dt><dd>children</dd><dt>mouse</dt><dd>mice</dd></dl>', 5, '2026-05-15 09:26:16.418092+00', null), (6, 'přivlastňování', '<p>Kromě přivlastňovacích zájmen (my, your, his, her, its, our, their) se v angličtině přivlastňuje pomocí apostrofu a -s:</p><br /><dl><dt>Tomova kniha</dt><dd>Tom''s book</dd></dl><br /><p>U množného čísla zakončeného na -s se používá pouze apostrof:</p><br /><dl><dt>pokoj studentů</dt><dd>students'' room</dd></dl>', 6, '2026-05-15 09:26:30.214854+00', null), (7, 'členy', '<p>V angličtině rozlišujeme <b>neurčitý člen</b> (<b>a / an</b>) a <b>určitý člen</b> (<b>the</b>).</p><br /><p><b>A / an</b> používáme u počitatelného podstatného jména v jednotném čísle, když o něm mluvíme poprvé nebo obecně.<b>An</b> píšeme před výslovností začínající samohláskou, jinak používáme <b>a</b>.</p><br /><dl><dt>učitel</dt><dd>a teacher</dd><dt>jablka</dt><dd>an apple</dd></dl><br /><p><b>The</b> používáme, když je věc konkrétní, známá z kontextu nebo už byla zmíněna:</p><br /><dl><dt>ten učitel</dt><dd>the teacher</dd></dl><br /><p>U množného čísla a u nepočitatelných podstatných jmen často člen nepoužíváme, pokud mluvíme obecně:</p><br /><dl><dt>učitelé</dt><dd>teachers</dd><dt>chleba</dt><dd>bread</dd></dl>', 7, '2026-05-15 09:26:49.289688+00', null), (8, 'čísla', '<p><b>Čísla 13 až 19</b> se tvoří příponou <b>-teen</b></p><br /><dl><dt>čtrnáct</dt><dd>fourteen</dd></dl><br /><p><b>Desítky</b> od 30 výše se obvykle tvoří příponou <b>-ty</b></p><br /><dl><dt>čtyřicet</dt><dd>fourty</dd></dl><br /><p><b>Složená čísla</b> se tvoří spojením stovek desítek číslic</p><br /><dl><dt>sto dvacet jedna</dt><dd>one hundred twenty-one</dd></dl><br /><p><b>Řadové číslovky</b> vyjadřují pořadí. U first, second, third jde o nepravidelné tvary, od 4 výše se obvykle tvoří příponou <b>-th</b></p><br /><dl><dt>čtvrtý</dt><dd>fourth</dd></dl><br /><p><b>Zlomky</b> od 3 dále se obvykle tvoří jako <b>číslo + příslušná řadová číslovka</b></p><br /><dl><dt>jedna čtvrtina</dt><dd>one fourth</dd></dl><br /><p><b>Desetinná čísla</b> čteme s výrazem <b>point</b></p><br /><dl><dt>osm celých pět</dt><dd>eight point five</dd></dl>', 8, '2026-05-15 09:27:20.13483+00', null), (9, 'čas a datumy', '<p><b>Datumy</b> v angličtině se obvykle píší ve formátu měsíc-den-rok (January 1, 2020). Pro zkrácenou formu se používá číslo měsíce a dne (1/1/2020).</p><br /><p><b>Čas</b> se v angličtině často uvádí ve 12hodinovém formátu s označením AM (ante meridiem) pro dopoledne a PM (post meridiem) pro odpoledne. Například 3:00 PM znamená 15:00.</p>', 9, '2026-05-15 11:13:34.864301+00', null), (10, 'předložky času in, on, at', '<p><b>In</b> používáme pro delší časové úseky jako měsíce, roky, roční období a delší části dne:</p><br /><dl><dt>v lednu</dt><dd>in January</dd></dl><br /><p><b>On</b> používáme pro konkrétní dny a data:</p><br /><dl><dt>v pondělí</dt><dd>on Monday</dd></dl><br /><p><b>At</b> používáme pro konkrétní časy a některé výrazy jako at night:</p><br /><dl><dt>v deset hodin</dt><dd>at ten o&#x27;clock</dd></dl>', 10, '2026-05-15 11:13:34.864301+00', null), (11, 'předložky místa in, on, at', '<p><b>In</b> používáme pro označení umístění uvnitř něčeho:</p><br /><dl><dt>v krabici</dt><dd>in the box</dd></dl><br /><p><b>On</b> používáme pro označení umístění na povrchu něčeho:</p><br /><dl><dt>na stole</dt><dd>on the table</dd></dl><br /><p><b>At</b> používáme pro označení konkrétního místa nebo bodu:</p><br /><dl><dt>u školy</dt><dd>at the school</dd></dl>', 11, '2026-05-15 11:13:34.864301+00', null), (12, 'přítomný čas prostý', '<p><b>Přítomný čas prostý (present simple)</b> používáme pro popis obecných pravd, zvyků a pravidelných činností. Tvoří se přidáním -s nebo -es u třetí osoby jednotného čísla (he, she, it) a základní tvar slovesa pro ostatní osoby.</p><br /><dl><dt>já pracuji</dt><dd>I work</dd><dt>ty pracuješ</dt><dd>you work</dd><dt>on pracuje</dt><dd>he works</dd><dt>ona pracuje</dt><dd>she works</dd><dt>to pracuje</dt><dd>it works</dd><dt>my pracujeme</dt><dd>we work</dd><dt>vy pracujete</dt><dd>you work</dd><dt>oni pracují</dt><dd>they work</dd></dl>', 12, '2026-05-15 11:13:34.864301+00', null), (13, 'přítomný čas prostý - zápor', '<p>Pro tvoření záporu v přítomném čase prostém používáme pomocné sloveso <b>do</b> (pro I, you, we, they) nebo <b>does</b> (pro he, she, it) a základní tvar slovesa s negací <b>not</b>.</p><br /><dl><dt>já nepracuji</dt><dd>I do not work</dd><dt>ty nepracuješ</dt><dd>you do not work</dd><dt>on nepracuje</dt><dd>he does not work</dd><dt>my nepracujeme</dt><dd>we do not work</dd><dt>vy nepracujete</dt><dd>you do not work</dd><dt>oni nepracují</dt><dd>they do not work</dd></dl><br /><p>Běžně se používá zkrácený tvar <b>don''t</b> (pro I, you, we, they) nebo <b>doesn''t</b> (pro he, she, it).</p><br /><dl><dt>já nepracuji</dt><dd>I don&#x27;t work</dd><dt>ty nepracuješ</dt><dd>you don&#x27;t work</dd><dt>on nepracuje</dt><dd>he doesn&#x27;t work</dd><dt>my nepracujeme</dt><dd>we don&#x27;t work</dd><dt>vy nepracujete</dt><dd>you don&#x27;t work</dd><dt>oni nepracují</dt><dd>they don&#x27;t work</dd></dl>', 13, '2026-05-15 11:13:34.864301+00', null), (14, 'pravidlo jednoho záporu', '<p>V angličtině se obvykle používá pravidlo jednoho záporu, což znamená, že v jedné větě by měl být pouze jeden zápor. Pokud použijeme více záporů, může to vést k nejasnostem a dvojímu zápornému významu.</p><br /><dl><dt>Nemám jablko.</dt><dd>I don&#x27;t have an apple.</dd><dt>Nemám jablko.</dt><dd>I don&#x27;t have any apple.</dd><dt>Nemám jablko.</dt><dd>I have no apple.</dd></dl>', 14, '2026-05-15 11:13:34.864301+00', null), (15, 'zvratná zájmena', '<p><b>Zvratná zájmena</b> se používají, když podmět a předmět věty jsou stejné osoby nebo věci. Tvoří se přidáním přípony <b>-self</b> pro jednotné číslo a <b>-selves</b> pro množné číslo k osobním zájmenům.</p><br /><dl><dt>já sám</dt><dd>myself</dd><dt>ty sám</dt><dd>yourself</dd><dt>on sám</dt><dd>himself</dd><dt>ona sama</dt><dd>herself</dd><dt>to samo</dt><dd>itself</dd><dt>my sami</dt><dd>ourselves</dd><dt>vy sami</dt><dd>yourselves</dd><dt>oni sami</dt><dd>themselves</dd></dl>', 15, '2026-05-15 11:13:34.864301+00', null), (16, 'zájmena v předmětu', '<p><b>Zájmena v předmětu</b> se používají jako předmět věty, tedy pro označení osoby nebo věci, která je ovlivněna dějem.</p><br /><dl><dt>já</dt><dd>me</dd><dt>ty</dt><dd>you</dd><dt>on</dt><dd>him</dd><dt>ona</dt><dd>her</dd><dt>to</dt><dd>it</dd><dt>my</dt><dd>us</dd><dt>vy</dt><dd>you</dd><dt>oni</dt><dd>them</dd></dl>', 16, '2026-05-15 11:13:34.864301+00', null);